mapper.select:
SELECT d.* FROM distributors d
LEFT JOIN users u ON d.user_id = u.id
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR d.invite_code LIKE CONCAT('%', #{keyword}, '%'))
AND d.status = #{status}
ORDER BY d.id DESC LIMIT #{size} OFFSET #{page}

mapper.update:
UPDATE distributors

    level_id = #{levelId},
    status = #{status},
    approved = #{approved},
    updated_at = #{updatedAt}

WHERE id = #{id}
